const items = $input.all();

// Group targets by user_id + company for batch processing
const grouped = {};
for (const item of items) {
  const key = `${item.json.user_id}__${item.json.company_name}`;
  if (!grouped[key]) {
    grouped[key] = {
      user_id: item.json.user_id,
      company_id: item.json.company_id,
      company_name: item.json.company_name,
      targets: []
    };
  }
  grouped[key].targets.push({
    platform: item.json.platform,
    target_identifier: item.json.target_identifier
  });
}

return Object.values(grouped).map(g => ({ json: g }));

const group = $('Group by User+Company').item.json;
const existingUrls = new Set($('Get Existing URLs').all().map(i => i.json.source_url));

// Build scrape tasks for each platform
const tasks = [];
for (const target of group.targets) {
  if (target.platform === 'g2') {
    tasks.push({
      user_id: group.user_id,
      company_id: group.company_id,
      company_name: group.company_name,
      platform: 'g2',
      scrape_url: target.target_identifier,
      existing_urls: [...existingUrls]
    });
  } else if (target.platform === 'reddit') {
    tasks.push({
      user_id: group.user_id,
      company_id: group.company_id,
      company_name: group.company_name,
      platform: 'reddit',
      scrape_url: target.target_identifier,
      existing_urls: [...existingUrls]
    });
  } else if (target.platform === 'capterra') {
    tasks.push({
      user_id: group.user_id,
      company_id: group.company_id,
      company_name: group.company_name,
      platform: 'capterra',
      scrape_url: target.target_identifier,
      existing_urls: [...existingUrls]
    });
  }
}

return tasks.map(t => ({ json: t }));
